    public Object dialog()
    {
        Object ret = next dialog();
    
        if(this.fieldList)
        {
            MapEnumerator   enumerator = this.fieldList.getEnumerator();
            fieldId         locField;
            DialogField     diagField;

            if(this.sourceTable is PurchTable)
            {
                while(enumerator.moveNext())
                {
                    if(enumerator.currentKey()==fieldNum(PurchTable,DefaultDimension))
                    {
                        locField    = enumerator.currentKey();
                        diagField   = enumerator.currentValue();
                        diagField.value(1);
                        diagField.enabled(false);
                    }
                }
                if(locField)
                {
                    //Boolean is mandatory below otherwhise it bug
                    boolean isRemoved  = this.fieldList.remove(locField);
                    boolean isInserted = this.fieldList.insert(locField,diagField);
                }
            }
        }
        return ret;
    }
